var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"후우…… 관리자님과 면담하는 건 항상 긴장되는군.","JPN":"ふう……管理者様との面談はいつも緊張するな。","ENG":"Whew... It is always nerve-racking to go into a meeting with the Administrator.","TWN":"呼……每次和管理者談話都好緊張。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"보고가 너무 길어졌어. 시간을 할애해 주신다고 나도 모르게 너무 들뜬 건가.","JPN":"報告が長引きすぎた。時間を割いてくださったことに思わず浮かれすぎてしまったか。","ENG":"My report went on for too long. Perhaps I got excited after hearing that he was going to give me time.","TWN":"但這次有點報告太久，是因為管理者說他特別抽時間出來，所以我一時興奮講得太忘我嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아직 업무 중인 직원들도 있을 테니…… 잠시 대기하다 가야겠군.","JPN":"まだ仕事が終わっていない社員たちもいるだろうし……しばらくここで待機してから出よう。","ENG":"Since there are employees here still working... I should stay for a while before heading back.","TWN":"現在應該還有其他員工在辦公吧……我等一下再離開好了。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……이 방도 꽤 자주 쓰게 됐어.","JPN":"……この部屋にもかなりの頻度で来るようになったものだ。","ENG":"...This room practically feels like mine now.","TWN":"……這個房間也很有歷史呢。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"힐데 전대장님과도 회포를 풀고 싶다만…… 당분간은 어렵겠지.","JPN":"ヒルデ戦隊長とのわだかまりも解きたいが……当分ば難しいだろう。","ENG":"Although I would like to catch up on old times with Commander Hilde... That would be difficult for the time being.","TWN":"我也很想和希爾德戰隊長敘敘舊……不過短時間內應該有困難。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래. 지금은 내 몸을 확실하게 통제하는 게 우선이야.","JPN":"そうだな。今は自分の身体を完璧にコントロールすることが先だ。","ENG":"Right. But my priority should be to take complete control over my body for now.","TWN":"嗯，現在最重要的是要控制好我的身體。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음? 이 소리는…… 캐비닛 쪽인가?","JPN":"うん？　この音は……キャビネットの方か？","ENG":"Mm? That sound... Is it coming from the cabinet?","TWN":"嗯？這個聲音是……是櫃子那裡嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"사무실에서 동물이라도 키우는 건가?","JPN":"オフィスで動物でも飼っているのか？","ENG":"Do they keep pets in the office?","TWN":"辦公室裡有養動物嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHILDREN_BARCODE_NULL_NULL","text":{"KOREA":"푸하아!","JPN":"ぷはっ！","ENG":"Puaah!","TWN":"噗哈哈！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"아앗! 아인, 새로운 언니야!","JPN":"ああっ！　アイン、新しいお姉ちゃんだよ！","ENG":"Oh! Eins! It's a new Sister!","TWN":"喔！艾茵，有新的姊姊！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"야아! 내가 먼저 말하려고 한 건데!","JPN":"もう！　あたしが先に言おうとしていたのに！","ENG":"Hey! I was going to say that first!","TWN":"可惡！你幹嘛搶我的話！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"헤헤, 아인보다 내가 더 빨랐어~","JPN":"へへっ、アインよりぼくの方が早かったもん～","ENG":"Hee hee, I was faster than you, Eins!","TWN":"嘿嘿，我比艾茵還要快～"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"흥. 그런 거 가지고 좋아하지 마, 바보야. 어린애도 아니구.","JPN":"ふん、そんなことで喜ばないでよ、バカ。子どもじゃあるまいし。","ENG":"Hmph. Don't be so smug about that, stupid. That's so childish.","TWN":"哼，傻瓜，這有什麼好開心的，又不是小朋友。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너희들은…… 제프티 바이오테크에서 도망쳐 나왔다던?","JPN":"君たちは……ジェフティ・バイオテックから逃げ出してきたという？","ENG":"Aren't you two... the ones who ran away from Jehuty Biotech?","TWN":"你們是……從傑夫堤生物科技逃出來的？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"응. 맞아. 나는 아인.","JPN":"うん、そうだよ。あたしはアイン。","ENG":"Yup. That's right. I'm Eins.","TWN":"對，我是艾茵。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"나는 츠바이야~","JPN":"ぼくはツヴァイだよ～","ENG":"And I'm Zwei!","TWN":"我是茨粨～"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……그렇군. 무사하게 지내고 있다니 다행이다.","JPN":"……そうか。元気に過ごしているようでなによりだ。","ENG":"...I see. I'm relieved to see that you two are doing well.","TWN":"……是嗎，看到你們都沒事，我覺得很安慰。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너희와 비슷한 처지인 사람들을 알고 있어. 너희들과 만나면 무척 반가워할 거다.","JPN":"君たちと同じような境遇の者たちを知っている。君たちに会えばきっと喜ぶだろう。","ENG":"I know a few people who were in a similar situation as yours. I'm sure they'll be more than glad to meet you.","TWN":"我認識一些和你們有相同處境的人，他們見到你們一定會很開心。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};